FROM revenue
WHERE revenue_id = 0 AND entity_id = 0;

external_knowledge:
- 'Park rangers' refer to users with the role 'park ranger'.;
- 'Captains of the gold fleet' metaphorically represents park rangers who manage departments or areas that generate significant revenue.;
- 'Steering their departments' implies the management or oversight of specific departments.;
- 'Treasure' metaphorically represents the total revenue accumulated by departments. The greater the revenue, the richer the 'treasure'.;
- 'Fiscal year of 2023' refers to the period from January 1, 2023, to December 31, 2023.;
- 'How rich was their haul?' means the total amount of revenue generated by each department. The results are to be listed from the richest haul to the least.;

sql:
SELECT activity_id, entity_id, SUM(revenue_amount) AS total_revenue
FROM revenue
GROUP BY activity_id, entity_id;

SELECT SUM(revenue_amount) AS total_revenue
FROM revenue
WHERE revenue_date BETWEEN '2023-05-01' AND '2023-05-31';

SELECT revenue_date, revenue_amount
FROM revenue
ORDER BY revenue_date ASC;
